transform_js:
function quantile(arr,q){
  var pos=(arr.length-1)*q;
  var lo=Math.floor(pos);
  var hi=Math.ceil(pos);
  if(lo===hi) return arr[lo];
  return arr[lo]*(hi-pos)+arr[hi]*(pos-lo);
}
function buildLevels(n){
  var levels=[];
  var p=0.25;
  var labels=['M','F','E','D','C','B','A'];
  var i=0;
  while(p>=1/(2*n) && i<labels.length){
    levels.push([p,1-p,labels[i],i]);
    p=p/2;
    i++;
  }
  return levels;
}
var groups=(rawData.groups||[]).map(function(g,idx){
  var vals=(g.values||[]).slice().map(Number).filter(function(v){return isFinite(v);}).sort(function(a,b){return a-b;});
  return {name:g.name||('Group '+(idx+1)),values:vals};
}).filter(function(g){return g.values.length>=8;});
groups=groups.map(function(g,idx){
  g.index=idx;
  return g;
});
var rows=[];
var medians=[];
var whiskers=[];
var globalMin=Infinity;
var globalMax=-Infinity;
groups.forEach(function(g){
  var vals=g.values;
  var levels=buildLevels(vals.length);
  levels.forEach(function(lv){
    var lo=quantile(vals,lv[0]);
    var hi=quantile(vals,lv[1]);
    rows.push({groupIndex:g.index,name:g.name,lo:lo,hi:hi,level:lv[3],letter:lv[2],lowerQ:lv[0],upperQ:lv[1]});
  });
  var median=quantile(vals,0.5);
  var q1=quantile(vals,0.25);
  var q3=quantile(vals,0.75);
  var iqr=q3-q1;
  var lowerFence=q1-1.5*iqr;
  var upperFence=q3+1.5*iqr;
  var whiskerLow=vals[0];
  var whiskerHigh=vals[vals.length-1];
  for(var i=0;i<vals.length;i++){
    if(vals[i]>=lowerFence){ whiskerLow=vals[i]; break; }
  }
  for(var j=vals.length-1;j>=0;j--){
    if(vals[j]<=upperFence){ whiskerHigh=vals[j]; break; }
  }
  medians.push({groupIndex:g.index,name:g.name,value:median});
  whiskers.push({groupIndex:g.index,name:g.name,low:whiskerLow,high:whiskerHigh});
  if(vals[0]<globalMin) globalMin=vals[0];
  if(vals[vals.length-1]>globalMax) globalMax=vals[vals.length-1];
});
if(!isFinite(globalMin)){ globalMin=0; globalMax=1; }
transformedData={groups:groups.map(function(g){return g.name;}),rows:rows,medians:medians,whiskers:whiskers,min:globalMin,max:globalMax};

echarts_js:
var rows=transformedData.rows||[];
var groups=transformedData.groups||[];
var medians=transformedData.medians||[];
var whiskers=transformedData.whiskers||[];
var palette=['#315b8a','#4a78a8','#6998c8','#8bb5df','#b1d0ef','#d7e7f8'];
var maxLevel=0;
rows.forEach(function(r){ if(r.level>maxLevel) maxLevel=r.level; });
var series=[];
series.push({
  name:'Whisker',
  type:'custom',
  coordinateSystem:'cartesian2d',
  data:whiskers.map(function(w){ return [w.groupIndex,w.low,w.high,w.name]; }),
  renderItem:function(params,api){
    var x=api.coord([api.value(0),api.value(1)])[0];
    var yLow=api.coord([api.value(0),api.value(1)])[1];
    var yHigh=api.coord([api.value(0),api.value(2)])[1];
    var band=api.size([1,0])[0];
    var cap=Math.max(8,band*0.16);
    return {
      type:'group',
      children:[
        {type:'line',shape:{x1:x,y1:yHigh,x2:x,y2:yLow},style:{stroke:'#5b6573',lineWidth:1.2}},
        {type:'line',shape:{x1:x-cap,y1:yHigh,x2:x+cap,y2:yHigh},style:{stroke:'#5b6573',lineWidth:1.2}},
        {type:'line',shape:{x1:x-cap,y1:yLow,x2:x+cap,y2:yLow},style:{stroke:'#5b6573',lineWidth:1.2}}
      ]
    };
  },
  z:2,
  silent:true,
  tooltip:{show:false}
});
for(var lv=maxLevel;lv>=0;lv--){
  var levelData=rows.filter(function(r){ return r.level===lv; }).map(function(r){
    return [r.groupIndex,r.lo,r.hi,r.level,r.name,r.lowerQ,r.upperQ,r.letter];
  });
  series.push({
    name:'LV-'+lv,
    type:'custom',
    coordinateSystem:'cartesian2d',
    data:levelData,
    renderItem:function(params,api){
      var x=api.coord([api.value(0),api.value(1)])[0];
      var y1=api.coord([api.value(0),api.value(1)])[1];
      var y2=api.coord([api.value(0),api.value(2)])[1];
      var level=api.value(3);
      var band=api.size([1,0])[0];
      var width=Math.max(12,band*(0.82-level*0.1));
      return {
        type:'rect',
        shape:{x:x-width/2,y:Math.min(y1,y2),width:width,height:Math.max(1,Math.abs(y2-y1))},
        style:{
          fill:palette[Math.min(level,palette.length-1)],
          stroke:'#ffffff',
          lineWidth:1,
          shadowBlur:level===0?4:0,
          shadowColor:'rgba(0,0,0,0.10)'
        }
      };
    },
    z:10+(maxLevel-lv)
  });
}
series.push({
  name:'Median',
  type:'custom',
  coordinateSystem:'cartesian2d',
  data:medians.map(function(m){ return [m.groupIndex,m.value,m.name]; }),
  renderItem:function(params,api){
    var x=api.coord([api.value(0),api.value(1)])[0];
    var y=api.coord([api.value(0),api.value(1)])[1];
    var band=api.size([1,0])[0];
    var half=Math.max(10,band*0.18);
    return {
      type:'group',
      children:[
        {type:'line',shape:{x1:x-half,y1:y,x2:x+half,y2:y},style:{stroke:'#d1495b',lineWidth:2.2}},
        {type:'circle',shape:{cx:x,cy:y,r:3.2},style:{fill:'#d1495b',stroke:'#ffffff',lineWidth:1}}
      ]
    };
  },
  z:40
});
var minVal=transformedData.min;
var maxVal=transformedData.max;
var pad=(maxVal-minVal)*0.10;
if(!isFinite(pad)||pad<=0){ pad=1; }
option={
  backgroundColor:'#fcfcfd',
  title:{
    text:'巨大データの裾を読む (Letter-Value Plot)',
    left:'center',
    top:10,
    textStyle:{fontSize:18,fontWeight:'bold',color:'#1f2d3d'}
  },
  grid:{left:72,right:28,top:68,bottom:58,containLabel:false},
  tooltip:{
    trigger:'item',
    backgroundColor:'rgba(255,255,255,0.96)',
    borderColor:'#d7deea',
    borderWidth:1,
    textStyle:{color:'#223'},
    formatter:function(p){
      if(p.seriesName==='Median'){
        return p.value[2]+'<br/>中央値: '+p.value[1];
      }
      if(p.seriesName==='Whisker'){
        return p.value[3]+'<br/>ひげ: '+p.value[1]+' ～ '+p.value[2];
      }
      return p.value[4]
        +'<br/>範囲: '+p.value[1]+' ～ '+p.value[2]
        +'<br/>分位: '+(p.value[5]*100)+'% ～ '+(p.value[6]*100)+'%'
        +'<br/>Letter: '+p.value[7];
    }
  },
  xAxis:{
    type:'category',
    data:groups,
    axisTick:{show:false},
    axisLine:{lineStyle:{color:'#7c8796'}},
    axisLabel:{color:'#334155',margin:12,fontSize:12}
  },
  yAxis:{
    type:'value',
    name:'Value',
    nameLocation:'middle',
    nameGap:50,
    min:minVal-pad,
    max:maxVal+pad,
    axisLine:{show:false},
    axisTick:{show:false},
    axisLabel:{color:'#475569'},
    splitLine:{show:true,lineStyle:{color:'#e8edf5'}}
  },
  series:series
};
